<template>
  <div>
    <div v-if="tasks.length === 0" class="p-4 md:p-8 bg-eerie-black rounded-lg shadow-md text-center">
      <div class="w-full md:max-w-2xl md:mx-auto">
        <Icon icon="heroicons:clipboard-document-list-20-solid" class="w-16 h-16 md:w-20 md:h-20 mx-auto mb-4 text-moonstone" />
        <h2 class="text-xl md:text-2xl font-bold text-gray-100 mb-3">Willkommen bei Lovely Reminder</h2>
        <div class="text-gray-300 space-y-3 text-left">
          <p class="text-sm md:text-base">Deine Aufgaben mit reaktiven Timern. Erledige eine Aufgabe und sie erscheint nach deiner gewählten Frist wieder.</p>
          <div class="bg-gray-700 p-3 md:p-4 rounded-lg">
            <h3 class="font-semibold text-moonstone mb-2 text-sm md:text-base">So funktioniert's:</h3>
            <ol class="list-decimal list-inside space-y-1.5 text-xs md:text-sm">
              <li>Füge Aufgaben mit einem <strong>reaktiven Timer</strong> hinzu (Tage bis zur Wiederkehr)</li>
              <li>Hake erledigte Aufgaben ab – sie werden durchgestrichen</li>
              <li>Nach den gesetzten Tagen wird die Aufgabe automatisch wieder aktiv</li>
            </ol>
          </div>
          <NuxtLink to="/task-add" class="btn-primary px-5 py-3 inline-flex items-center mt-4">
            <Icon icon="heroicons:plus-20-solid" class="w-5 h-5 mr-2" />
            Erste Aufgabe hinzufügen
          </NuxtLink>
        </div>
      </div>
    </div>

    <div v-else class="space-y-4 md:space-y-6">
      <div class="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
        <div>
          <h2 class="text-lg md:text-xl font-bold text-gray-100">Deine Aufgaben</h2>
          <p class="text-sm text-gray-400 mt-0.5">Denk daran: Du machst es für euch beide. ♥</p>
        </div>
          <NuxtLink to="/task-add" class="btn-add px-4 py-2 inline-flex items-center text-sm self-start md:self-center">
          <Icon icon="heroicons:plus-20-solid" class="w-5 h-5 mr-2" />
          Aufgabe hinzufügen
        </NuxtLink>
      </div>

      <div v-for="task in tasks" :key="task.id" class="bg-eerie-black rounded-lg shadow-md p-4 md:p-5">
        <div class="flex flex-row items-start gap-3 md:gap-4">
          <input
            type="checkbox"
            :checked="isTaskCompleted(task)"
            :disabled="isTaskCompleted(task)"
            :aria-label="isTaskCompleted(task) ? `Erledigt: ${task.text}` : `Als erledigt markieren: ${task.text}`"
            class="mt-1 w-5 h-5 md:w-6 md:h-6 rounded border-2 flex-shrink-0 accent-green-500"
            :class="isTaskCompleted(task) ? 'cursor-default opacity-90' : 'cursor-pointer'"
            :style="{ borderColor: 'var(--color-border)' }"
            @change="completeTask(task.id)"
          >
          <div class="flex-1 min-w-0">
            <p
              class="text-gray-200 text-sm md:text-base leading-relaxed"
              :class="{ 'line-through opacity-70': isTaskCompleted(task) }"
            >
              {{ task.text }}
            </p>
            <div class="flex flex-wrap items-center gap-2 mt-2 text-xs text-gray-400">
              <span v-if="isTaskCompleted(task) && daysUntilReactivation(task) !== null">
                <template v-if="daysUntilReactivation(task) === 0">Heute wieder aktiv</template>
                <template v-else-if="daysUntilReactivation(task) === 1">1 Tag bis zur Reaktivierung</template>
                <template v-else>{{ daysUntilReactivation(task) }} Tage bis zur Reaktivierung</template>
              </span>
              <span v-else>Alle {{ task.reactiveDays }} {{ task.reactiveDays === 1 ? 'Tag' : 'Tage' }}</span>
            </div>
          </div>
          <button
            type="button"
            class="btn-delete flex-shrink-0"
            aria-label="Delete task"
            @click="deleteTask(task.id)"
          >
            <Icon icon="heroicons:trash-20-solid" class="w-5 h-5" />
          </button>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { Icon } from '@iconify/vue';
import { useTasks } from '~/composables/useTasks';

definePageMeta({ title: 'Dashboard' });

const { tasks, loadFromLocalStorage, checkAndReactivateTasks, completeTask, deleteTask, isTaskCompleted, daysUntilReactivation } = useTasks();

onMounted(() => {
  loadFromLocalStorage();
  checkAndReactivateTasks();
});
</script>
